import{_ as a}from"./chunks/homepage.DZZjIHGg.js";import{_ as o,a as t}from"./chunks/deletecard.JRCLAEit.js";import{_ as i,o as l,c as r,ae as s}from"./chunks/framework.C00B0EYs.js";const b=JSON.parse('{"title":"首页","description":"在首页完成项目新建、打开、导入、搜索与管理。","frontmatter":{"title":"首页","description":"在首页完成项目新建、打开、导入、搜索与管理。"},"headers":[],"relativePath":"zh/docs/guide/home.md","filePath":"zh/docs/guide/home.md"}'),n={name:"zh/docs/guide/home.md"};function p(d,e,h,c,m,u){return l(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="首页" tabindex="-1">首页 <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页&quot;">​</a></h1><p>首页（Home）是你的项目中枢。你可以在这里创建新工作、重新打开已有文件、导入外部 <code>.msep</code> 文件，以及浏览最近项目。</p><p><img src="'+a+'" alt="Motor Sound Editor 首页项目画廊"></p><h2 id="侧栏操作" tabindex="-1">侧栏操作 <a class="header-anchor" href="#侧栏操作" aria-label="Permalink to &quot;侧栏操作&quot;">​</a></h2><p>左侧栏是动作导向的入口区，包含开始或恢复工作的主要操作：</p><ul><li><strong>新建项目 New Project</strong>：打开新建项目弹窗，并创建新的工作文档。</li><li><strong>打开文件 Open File</strong>：从磁盘打开已有 <code>.msep</code> 文件。</li><li><strong>导入文件 Import File</strong>：通过应用的导入流程引入 <code>.msep</code> 文件，也可以将 <code>.msep</code> 直接拖入首页完成导入。</li><li><strong>设置 Settings</strong>：当前版本尚未提供完成版设置界面。</li></ul><h2 id="最近项目区域" tabindex="-1">最近项目区域 <a class="header-anchor" href="#最近项目区域" aria-label="Permalink to &quot;最近项目区域&quot;">​</a></h2><p><img src="'+o+'" alt="项目卡片"></p><p>主区域会以卡片形式展示最近项目。每张卡片通常包含：</p><ul><li>项目名称</li><li>最后修改时间</li><li>音轨预览缩略图</li></ul><p>这个区域的设计目标是减少上下文切换。你可以通过视觉识别快速回到之前的项目。</p><h2 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h2><p>搜索框会按文本过滤最近项目列表。</p><p>如果你的命名规范比较一致，例如按车型、运营方或制作阶段命名，搜索会特别高效。</p><h2 id="排序" tabindex="-1">排序 <a class="header-anchor" href="#排序" aria-label="Permalink to &quot;排序&quot;">​</a></h2><p>首页至少支持两种常用排序方式：</p><ul><li><strong>日期 Date</strong>：适合回到最近编辑过的项目。</li><li><strong>名称 Name</strong>：适合并行管理多个项目，并依赖命名规则查找。</li></ul><p>活跃制作期间通常优先按日期，资料库式回看通常优先按名称。</p><h2 id="打开项目" tabindex="-1">打开项目 <a class="header-anchor" href="#打开项目" aria-label="Permalink to &quot;打开项目&quot;">​</a></h2><p>你可以通过以下入口打开项目：</p><ul><li><strong>打开文件 Open File</strong>：选择 <code>.msep</code> 文件后直接打开。</li><li><strong>项目卡片 Project Card</strong>：点击最近项目区域中的项目卡片。</li></ul><p>只要文件有效，应用就会将项目元数据、轨道、曲线和打包音频加载到编辑器中。</p><h2 id="从最近列表移除项目" tabindex="-1">从最近列表移除项目 <a class="header-anchor" href="#从最近列表移除项目" aria-label="Permalink to &quot;从最近列表移除项目&quot;">​</a></h2><p><img src="'+t+'" alt="删除卡片"></p><p>最近项目视图支持移除某条记录。你可以右击卡片打开菜单，再点击 <strong>Delete</strong>。</p><p>这个操作只影响“最近列表”，不会删除磁盘上的项目文件。常见使用场景包括：</p><ul><li>文件路径已经变更。</li><li>条目已经没有参考价值。</li><li>你希望清理最近项目面板。</li></ul><h2 id="新建项目字段" tabindex="-1">新建项目字段 <a class="header-anchor" href="#新建项目字段" aria-label="Permalink to &quot;新建项目字段&quot;">​</a></h2><p>创建新项目时，应用会要求填写核心元数据和模拟器默认参数。通常包括：</p><ul><li>项目名称</li><li>最高速度</li><li>加速度</li></ul><p>这些值不只是标签，它们也会影响曲线速度范围约束，以及实时预览系统对项目的解释方式。</p>',31)])])}const q=i(n,[["render",p]]);export{b as __pageData,q as default};
